class Eratosthenes {

public:

	vector<bool> primary(int N) {

		vector<bool> primary(N + 1, true);

		primary[0] = false;

		if (N == 0) return primary;

		primary[1] = false;

		for (int i = 1; i*i <= N; i++) if (primary[i]) for (int j = 2 * i; j <= N; j += i) primary[j] = false;

