		st.push({ root,root_from });



		while (!st.empty()) {

			int from = st.top().first;

			int from_from = st.top().second;

			st.pop();

			REP(i, edge[from].size()) {

				int to = edge[from][i];

				if (to != from_from) {

					depth[to] = depth[from] + 1;

					parent[to][0] = from;

					st.push({ to,from });

